// Spend Agent — SaaS & License Audit
const { scan_id, organization_id } = $input.first().json;
const findings = [
  { id: `${scan_id}-SP-001`, title: 'Duplicate Slack seats detected', risk: 'high', impact_annual: 18000, tab: 'spend' },
  { id: `${scan_id}-SP-002`, title: 'Unused Figma Pro licenses (12)', risk: 'medium', impact_annual: 3600, tab: 'spend' },
  { id: `${scan_id}-SP-003`, title: 'Redundant Zoom + Teams subscription', risk: 'critical', impact_annual: 24000, tab: 'spend' },
];
return [{ json: { agent: 'spend', scan_id, organization_id, findings, status: 'done', findings_count: findings.length } }];

// Resource Agent — Cloud Infrastructure Audit
const { scan_id, organization_id } = $input.first().json;
const findings = [
  { id: `${scan_id}-RS-001`, title: 'Idle EC2 t3.xlarge (eu-west-1)', risk: 'critical', impact_annual: 42000, tab: 'resources' },
  { id: `${scan_id}-RS-002`, title: 'Unattached EBS volumes (23 GB)', risk: 'medium', impact_annual: 2760, tab: 'resources' },
  { id: `${scan_id}-RS-003`, title: 'Oversized RDS db.r5.2xlarge', risk: 'high', impact_annual: 31200, tab: 'resources' },
];
return [{ json: { agent: 'resource', scan_id, organization_id, findings, status: 'done', findings_count: findings.length } }];

// SLA Agent — Contract Compliance Audit
const { scan_id, organization_id } = $input.first().json;
const findings = [
  { id: `${scan_id}-SL-001`, title: 'Support SLA breach – Ticket #8821', risk: 'critical', impact_annual: 15000, tab: 'sla' },
  { id: `${scan_id}-SL-002', title: 'API uptime SLA below 99.9% threshold', risk: 'high', impact_annual: 8400, tab: 'sla' },
];
return [{ json: { agent: 'sla', scan_id, organization_id, findings, status: 'done', findings_count: findings.length } }];

// FinOps Agent — Billing & Invoice Audit
const { scan_id, organization_id } = $input.first().json;
const findings = [
  { id: `${scan_id}-FO-001`, title: 'Invoice discrepancy – AWS Nov billing', risk: 'high', impact_annual: 9600, tab: 'finops' },
];
return [{ json: { agent: 'finops', scan_id, organization_id, findings, status: 'done', findings_count: findings.length } }];

// Aggregate all sub-agent results for TrustKit
const allItems = $input.all();
const allFindings = allItems.flatMap(item => item.json.findings || []);
const summary = {
  scan_id: allItems[0]?.json.scan_id,
  total_findings: allFindings.length,
  agents_completed: allItems.map(i => i.json.agent),
  findings: allFindings,
  orchestrator: 'TrustKit v1.2',
  completed_at: new Date().toISOString(),
};
return [{ json: summary }];
